// // This module decrements the counter on the rising edge of the clock.
module counter_4bit(clk, rst, q);

    input clk;
    input rst;
    output [3:0] q;
    reg [3:0] q;

    always @(posedge clk or posedge rst)
    begin
        if (rst)
            q <= 4'b0000;
        else
            q <= q + 1;
    end

endmodule
